69	/// Executes a shell command with the requested sandbox settings.
70	pub fn execute_bash(input: BashCommandInput) -> io::Result<BashCommandOutput> {
71	    let cwd = env::current_dir()?;
72	    let sandbox_status = sandbox_status_for_input(&input, &cwd);
73	
74	    if input.run_in_background.unwrap_or(false) {
75	        let mut child = prepare_command(&input.command, &cwd, &sandbox_status, false);
76	        let child = child
77	            .stdin(Stdio::null())
78	            .stdout(Stdio::null())
79	            .stderr(Stdio::null())
80	            .spawn()?;
81	
82	        return Ok(BashCommandOutput {
83	            stdout: String::new(),
84	            stderr: String::new(),
85	            raw_output_path: None,
86	            interrupted: false,
87	            is_image: None,
88	            background_task_id: Some(child.id().to_string()),
89	            backgrounded_by_user: Some(false),
90	            assistant_auto_backgrounded: Some(false),
91	            dangerously_disable_sandbox: input.dangerously_disable_sandbox,
92	            return_code_interpretation: None,
93	            no_output_expected: Some(true),
94	            structured_content: None,
95	            persisted_output_path: None,
96	            persisted_output_size: None,
97	            sandbox_status: Some(sandbox_status),
98	        });
99	    }
100	
101	    let runtime = Builder::new_current_thread().enable_all().build()?;
102	    runtime.block_on(execute_bash_async(input, sandbox_status, cwd))
103	}
