105	async fn execute_bash_async(
106	    input: BashCommandInput,
107	    sandbox_status: SandboxStatus,
108	    cwd: std::path::PathBuf,
109	) -> io::Result<BashCommandOutput> {
110	    let mut command = prepare_tokio_command(&input.command, &cwd, &sandbox_status, true);
111	
112	    let output_result = if let Some(timeout_ms) = input.timeout {
113	        match timeout(Duration::from_millis(timeout_ms), command.output()).await {
114	            Ok(result) => (result?, false),
115	            Err(_) => {
116	                return Ok(BashCommandOutput {
117	                    stdout: String::new(),
118	                    stderr: format!("Command exceeded timeout of {timeout_ms} ms"),
119	                    raw_output_path: None,
120	                    interrupted: true,
121	                    is_image: None,
122	                    background_task_id: None,
123	                    backgrounded_by_user: None,
124	                    assistant_auto_backgrounded: None,
125	                    dangerously_disable_sandbox: input.dangerously_disable_sandbox,
126	                    return_code_interpretation: Some(String::from("timeout")),
127	                    no_output_expected: Some(true),
128	                    structured_content: None,
129	                    persisted_output_path: None,
130	                    persisted_output_size: None,
131	                    sandbox_status: Some(sandbox_status),
132	                });
133	            }
134	        }
135	    } else {
136	        (command.output().await?, false)
137	    };
138	
139	    let (output, interrupted) = output_result;
140	    let stdout = truncate_output(&String::from_utf8_lossy(&output.stdout));
141	    let stderr = truncate_output(&String::from_utf8_lossy(&output.stderr));
142	    let no_output_expected = Some(stdout.trim().is_empty() && stderr.trim().is_empty());
143	    let return_code_interpretation = output.status.code().and_then(|code| {
144	        if code == 0 {
145	            None
146	        } else {
147	            Some(format!("exit_code:{code}"))
148	        }
149	    });
150	
151	    Ok(BashCommandOutput {
152	        stdout,
153	        stderr,
154	        raw_output_path: None,
155	        interrupted,
156	        is_image: None,
157	        background_task_id: None,
158	        backgrounded_by_user: None,
159	        assistant_auto_backgrounded: None,
160	        dangerously_disable_sandbox: input.dangerously_disable_sandbox,
